if (is_using_ntt_form_)
    {
        if (!is_db_preprocessed_)
        {

            for (uint32_t i = 0; i < db_->size(); i++)
            {
                Plaintext tmp;
                evaluator_->ntt_fwd(db_->operator[](i), tmp, context_->crt_context()->first_parms_id());
                db_->operator[](i) = tmp;
            }

            is_db_preprocessed_ = true;
        }
    }
